   175→	saref := private.Kubernetes.Svcacct
   176→	podref := private.Kubernetes.Pod
   177→	noderef := private.Kubernetes.Node
   178→	secref := private.Kubernetes.Secret
   179→	// Make sure service account still exists (name and UID)
   180→	serviceAccount, err := v.getter.GetServiceAccount(namespace, saref.Name)
