   216→		if err != nil {
   217→			klog.V(4).Infof("Could not retrieve bound pod %s/%s for service account %s/%s: %v", namespace, podref.Name, namespace, saref.Name, err)
   218→			return nil, errors.New("service account token has been invalidated")
   219→		}
   220→		if podref.UID != string(pod.UID) {
   221→			klog.V(4).Infof("Pod UID no longer matches %s/%s: %q != %q", namespace, podref.Name, string(pod.UID), podref.UID)
   222→			return nil, fmt.Errorf("pod UID (%s) does not match service account pod ref claim (%s)", pod.UID, podref.UID)
   223→		}
