   242→			if !utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenNodeBindingValidation) {
   243→				klog.V(4).Infof("ServiceAccount token is bound to a Node object, but the node bound token validation feature is disabled")
   244→				return nil, fmt.Errorf("token is bound to a Node object but the %s feature gate is disabled", features.ServiceAccountTokenNodeBindingValidation)
   245→			}
   246→
   247→			node, err := v.getter.GetNode(noderef.Name)
   248→			if err != nil {
   249→				klog.V(4).Infof("Could not retrieve node object %q for service account %s/%s: %v", noderef.Name, namespace, saref.Name, err)
   250→				return nil, errors.New("service account token has been invalidated")
   251→			}
   252→			if noderef.UID != string(node.UID) {
   253→				klog.V(4).Infof("Node UID no longer matches %s: %q != %q", noderef.Name, string(node.UID), noderef.UID)
   254→				return nil, fmt.Errorf("node UID (%s) does not match service account node ref claim (%s)", node.UID, noderef.UID)
   255→			}
   256→			if node.DeletionTimestamp != nil && node.DeletionTimestamp.Time.Before(invalidIfDeletedBefore) {
   257→				klog.V(4).Infof("Node %q is deleted and awaiting removal for service account %s/%s", node.Name, namespace, saref.Name)
   258→				return nil, errors.New("service account token has been invalidated")
   259→			}
   260→			nodeName = noderef.Name
   261→			nodeUID = noderef.UID
   262→		}
   263→	}
   264→
   265→	// Check special 'warnafter' field for projected service account token transition.
   266→	warnafter := private.Kubernetes.WarnAfter
   267→	if warnafter != nil && *warnafter != 0 {
   268→		if nowTime.After(warnafter.Time()) {
