   273→		} else {
   274→			validTokensTotal.WithContext(ctx).Inc()
   275→		}
   276→	}
   277→
   278→	var jti string
   279→	if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenJTI) {
   280→		jti = public.ID
   281→	}
