    82→	pc := &privateClaims{
    83→		Kubernetes: kubernetes{
    84→			Namespace: sa.Namespace,
    85→			Svcacct: ref{
    86→				Name: sa.Name,
    87→				UID:  string(sa.UID),
    88→			},
    89→		},
    90→	}
    91→
    92→	if secret != nil && (node != nil || pod != nil) {
    93→		return nil, nil, fmt.Errorf("internal error, token can only be bound to one object type")
    94→	}
    95→	switch {
    96→	case pod != nil:
    97→		pc.Kubernetes.Pod = &ref{
    98→			Name: pod.Name,
    99→			UID:  string(pod.UID),
   100→		}
   101→		if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenPodNodeInfo) {
   102→			// if this is bound to a pod and the node information is available, persist that too
   103→			if node != nil {
   104→				pc.Kubernetes.Node = &ref{
   105→					Name: node.Name,
   106→					UID:  string(node.UID),
   107→				}
   108→			}
   109→		}
   110→	case secret != nil:
   111→		pc.Kubernetes.Secret = &ref{
   112→			Name: secret.Name,
   113→			UID:  string(secret.UID),
   114→		}
   115→	case node != nil:
   116→		if !utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenNodeBinding) {
   117→			return nil, nil, fmt.Errorf("token bound to Node object requested, but %q feature gate is disabled", features.ServiceAccountTokenNodeBinding)
   118→		}
   119→		pc.Kubernetes.Node = &ref{
   120→			Name: node.Name,
   121→			UID:  string(node.UID),
   122→		}
   123→	}
   124→
   125→	if warnafter != 0 {
   126→		pc.Kubernetes.WarnAfter = jwt.NewNumericDate(now.Add(time.Duration(warnafter) * time.Second))
   127→	}
   128→
   129→	return sc, pc, nil
   130→}
   131→
   132→func NewValidator(getter ServiceAccountTokenGetter) Validator[privateClaims] {
   133→	return &validator{
   134→		getter: getter,
   135→	}
   136→}
   137→
   138→type validator struct {
   139→	getter ServiceAccountTokenGetter
   140→}
   141→
   142→var _ = Validator[privateClaims](&validator{})
   143→
   144→func (v *validator) Validate(ctx context.Context, _ string, public *jwt.Claims, private *privateClaims) (*apiserverserviceaccount.ServiceAccountInfo, error) {
   145→	nowTime := now()
   146→	err := public.Validate(jwt.Expected{
   147→		Time: nowTime,
   148→	})
   149→	switch err {
   150→	case nil:
   151→		// successful validation
   152→
   153→	case jwt.ErrExpired:
   154→		return nil, errors.New("service account token has expired")
   155→
   156→	case jwt.ErrNotValidYet:
   157→		return nil, errors.New("service account token is not valid yet")
   158→
   159→	case jwt.ErrIssuedInTheFuture:
   160→		return nil, errors.New("service account token is issued in the future")
   161→
   162→	// our current use of jwt.Expected above should make these cases impossible to hit
   163→	case jwt.ErrInvalidAudience, jwt.ErrInvalidID, jwt.ErrInvalidIssuer, jwt.ErrInvalidSubject:
   164→		klog.Errorf("service account token claim validation got unexpected validation failure: %v", err)
   165→		return nil, fmt.Errorf("service account token claims could not be validated: %w", err) // safe to pass these errors back to the user
   166→
   167→	default:
   168→		klog.Errorf("service account token claim validation got unexpected error type: %T", err)                         // avoid leaking unexpected information into the logs
   169→		return nil, errors.New("service account token claims could not be validated due to unexpected validation error") // return an opaque error
   170→	}
   171→
   172→	// consider things deleted prior to now()-leeway to be invalid
   173→	invalidIfDeletedBefore := nowTime.Add(-jwt.DefaultLeeway)
   174→	namespace := private.Kubernetes.Namespace
   175→	saref := private.Kubernetes.Svcacct
   176→	podref := private.Kubernetes.Pod
   177→	noderef := private.Kubernetes.Node
   178→	secref := private.Kubernetes.Secret
   179→	// Make sure service account still exists (name and UID)
   180→	serviceAccount, err := v.getter.GetServiceAccount(namespace, saref.Name)
   181→	if err != nil {
   182→		klog.V(4).Infof("Could not retrieve service account %s/%s: %v", namespace, saref.Name, err)
   183→		return nil, err
   184→	}
   185→
   186→	if string(serviceAccount.UID) != saref.UID {
   187→		klog.V(4).Infof("Service account UID no longer matches %s/%s: %q != %q", namespace, saref.Name, string(serviceAccount.UID), saref.UID)
   188→		return nil, fmt.Errorf("service account UID (%s) does not match claim (%s)", serviceAccount.UID, saref.UID)
   189→	}
   190→	if serviceAccount.DeletionTimestamp != nil && serviceAccount.DeletionTimestamp.Time.Before(invalidIfDeletedBefore) {
   191→		klog.V(4).Infof("Service account has been deleted %s/%s", namespace, saref.Name)
   192→		return nil, fmt.Errorf("service account %s/%s has been deleted", namespace, saref.Name)
   193→	}
   194→
   195→	if secref != nil {
   196→		// Make sure token hasn't been invalidated by deletion of the secret
   197→		secret, err := v.getter.GetSecret(namespace, secref.Name)
   198→		if err != nil {
   199→			klog.V(4).Infof("Could not retrieve bound secret %s/%s for service account %s/%s: %v", namespace, secref.Name, namespace, saref.Name, err)
   200→			return nil, errors.New("service account token has been invalidated")
   201→		}
   202→		if secref.UID != string(secret.UID) {
   203→			klog.V(4).Infof("Secret UID no longer matches %s/%s: %q != %q", namespace, secref.Name, string(secret.UID), secref.UID)
   204→			return nil, fmt.Errorf("secret UID (%s) does not match service account secret ref claim (%s)", secret.UID, secref.UID)
   205→		}
   206→		if secret.DeletionTimestamp != nil && secret.DeletionTimestamp.Time.Before(invalidIfDeletedBefore) {
   207→			klog.V(4).Infof("Bound secret is deleted and awaiting removal: %s/%s for service account %s/%s", namespace, secref.Name, namespace, saref.Name)
   208→			return nil, errors.New("service account token has been invalidated")
   209→		}
   210→	}
   211→
   212→	var podName, podUID string
   213→	if podref != nil {
   214→		// Make sure token hasn't been invalidated by deletion of the pod
   215→		pod, err := v.getter.GetPod(namespace, podref.Name)
   216→		if err != nil {
   217→			klog.V(4).Infof("Could not retrieve bound pod %s/%s for service account %s/%s: %v", namespace, podref.Name, namespace, saref.Name, err)
   218→			return nil, errors.New("service account token has been invalidated")
   219→		}
   220→		if podref.UID != string(pod.UID) {
   221→			klog.V(4).Infof("Pod UID no longer matches %s/%s: %q != %q", namespace, podref.Name, string(pod.UID), podref.UID)
   222→			return nil, fmt.Errorf("pod UID (%s) does not match service account pod ref claim (%s)", pod.UID, podref.UID)
   223→		}
   224→		if pod.DeletionTimestamp != nil && pod.DeletionTimestamp.Time.Before(invalidIfDeletedBefore) {
   225→			klog.V(4).Infof("Bound pod is deleted and awaiting removal: %s/%s for service account %s/%s", namespace, podref.Name, namespace, saref.Name)
   226→			return nil, errors.New("service account token has been invalidated")
   227→		}
   228→		podName = podref.Name
   229→		podUID = podref.UID
   230→	}
   231→
   232→	var nodeName, nodeUID string
   233→	if noderef != nil {
   234→		switch {
   235→		case podref != nil:
   236→			if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenPodNodeInfo) {
   237→				// for pod-bound tokens, just extract the node claims
   238→				nodeName = noderef.Name
   239→				nodeUID = noderef.UID
   240→			}
   241→		case podref == nil:
   242→			if !utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenNodeBindingValidation) {
   243→				klog.V(4).Infof("ServiceAccount token is bound to a Node object, but the node bound token validation feature is disabled")
   244→				return nil, fmt.Errorf("token is bound to a Node object but the %s feature gate is disabled", features.ServiceAccountTokenNodeBindingValidation)
   245→			}
   246→
   247→			node, err := v.getter.GetNode(noderef.Name)
   248→			if err != nil {
   249→				klog.V(4).Infof("Could not retrieve node object %q for service account %s/%s: %v", noderef.Name, namespace, saref.Name, err)
   250→				return nil, errors.New("service account token has been invalidated")
   251→			}
   252→			if noderef.UID != string(node.UID) {
   253→				klog.V(4).Infof("Node UID no longer matches %s: %q != %q", noderef.Name, string(node.UID), noderef.UID)
   254→				return nil, fmt.Errorf("node UID (%s) does not match service account node ref claim (%s)", node.UID, noderef.UID)
   255→			}
   256→			if node.DeletionTimestamp != nil && node.DeletionTimestamp.Time.Before(invalidIfDeletedBefore) {
   257→				klog.V(4).Infof("Node %q is deleted and awaiting removal for service account %s/%s", node.Name, namespace, saref.Name)
   258→				return nil, errors.New("service account token has been invalidated")
   259→			}
   260→			nodeName = noderef.Name
   261→			nodeUID = noderef.UID
   262→		}
   263→	}
   264→
   265→	// Check special 'warnafter' field for projected service account token transition.
   266→	warnafter := private.Kubernetes.WarnAfter
   267→	if warnafter != nil && *warnafter != 0 {
   268→		if nowTime.After(warnafter.Time()) {
   269→			secondsAfterWarn := nowTime.Unix() - warnafter.Time().Unix()
   270→			auditInfo := fmt.Sprintf("subject: %s, seconds after warning threshold: %d", public.Subject, secondsAfterWarn)
   271→			audit.AddAuditAnnotation(ctx, "authentication.k8s.io/stale-token", auditInfo)
   272→			staleTokensTotal.WithContext(ctx).Inc()
   273→		} else {
   274→			validTokensTotal.WithContext(ctx).Inc()
   275→		}
   276→	}
   277→
   278→	var jti string
   279→	if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenJTI) {
   280→		jti = public.ID
   281→	}
   282→	return &apiserverserviceaccount.ServiceAccountInfo{
   283→		Namespace:    private.Kubernetes.Namespace,
   284→		Name:         private.Kubernetes.Svcacct.Name,
   285→		UID:          private.Kubernetes.Svcacct.UID,
   286→		PodName:      podName,
   287→		PodUID:       podUID,
   288→		NodeName:     nodeName,
   289→		NodeUID:      nodeUID,
   290→		CredentialID: authenticationtokenjwt.CredentialIDForJTI(jti),
   291→	}, nil
   292→}
