    86→		StaticStringSlice(trimmedNameHeaders),
    87→		StaticStringSlice(trimmedUIDHeaders),
    88→		StaticStringSlice(trimmedGroupHeaders),
    89→		StaticStringSlice(trimmedExtraHeaderPrefixes),
    90→	), nil
    91→}
    92→
    93→func NewDynamic(nameHeaders, uidHeaders, groupHeaders, extraHeaderPrefixes StringSliceProvider) authenticator.Request {
    94→	return &requestHeaderAuthRequestHandler{
    95→		nameHeaders:         nameHeaders,
    96→		uidHeaders:          uidHeaders,
    97→		groupHeaders:        groupHeaders,
    98→		extraHeaderPrefixes: extraHeaderPrefixes,
    99→	}
   100→}
   101→
   102→func trimHeaders(headerNames ...string) ([]string, error) {
   103→	ret := []string{}
   104→	for _, headerName := range headerNames {
   105→		trimmedHeader := strings.TrimSpace(headerName)
   106→		if len(trimmedHeader) == 0 {
   107→			return nil, fmt.Errorf("empty header %q", headerName)
   108→		}
   109→		ret = append(ret, trimmedHeader)
   110→	}
   111→
   112→	return ret, nil
   113→}
   114→
   115→func NewDynamicVerifyOptionsSecure(verifyOptionFn x509request.VerifyOptionFunc, proxyClientNames, nameHeaders, uidHeaders, groupHeaders, extraHeaderPrefixes StringSliceProvider) authenticator.Request {
   116→	headerAuthenticator := NewDynamic(nameHeaders, uidHeaders, groupHeaders, extraHeaderPrefixes)
   117→
   118→	return x509request.NewDynamicCAVerifier(verifyOptionFn, headerAuthenticator, proxyClientNames)
   119→}
   120→
   121→func (a *requestHeaderAuthRequestHandler) AuthenticateRequest(req *http.Request) (*authenticator.Response, bool, error) {
   122→	name := headerValue(req.Header, a.nameHeaders.Value())
   123→	if len(name) == 0 {
   124→		return nil, false, nil
   125→	}
   126→	uid := headerValue(req.Header, a.uidHeaders.Value())
   127→	groups := allHeaderValues(req.Header, a.groupHeaders.Value())
   128→	extra := newExtra(req.Header, a.extraHeaderPrefixes.Value())
   129→
   130→	// clear headers used for authentication
   131→	ClearAuthenticationHeaders(req.Header, a.nameHeaders, a.uidHeaders, a.groupHeaders, a.extraHeaderPrefixes)
   132→
   133→	return &authenticator.Response{
   134→		User: &user.DefaultInfo{
   135→			Name:   name,
   136→			UID:    uid,
   137→			Groups: groups,
   138→			Extra:  extra,
   139→		},
   140→	}, true, nil
   141→}
   142→
   143→func ClearAuthenticationHeaders(h http.Header, nameHeaders, uidHeaders, groupHeaders, extraHeaderPrefixes StringSliceProvider) {
   144→	for _, headerName := range nameHeaders.Value() {
   145→		h.Del(headerName)
   146→	}
   147→	for _, headerName := range uidHeaders.Value() {
   148→		h.Del(headerName)
   149→	}
   150→	for _, headerName := range groupHeaders.Value() {
   151→		h.Del(headerName)
   152→	}
   153→	for _, prefix := range extraHeaderPrefixes.Value() {
   154→		for k := range h {
   155→			if hasPrefixIgnoreCase(k, prefix) {
   156→				delete(h, k) // we have the raw key so avoid relying on canonicalization
   157→			}
   158→		}
   159→	}
   160→}
   161→
   162→func hasPrefixIgnoreCase(s, prefix string) bool {
   163→	return len(s) >= len(prefix) && strings.EqualFold(s[:len(prefix)], prefix)
   164→}
   165→
   166→func headerValue(h http.Header, headerNames []string) string {
   167→	for _, headerName := range headerNames {
   168→		headerValue := h.Get(headerName)
   169→		if len(headerValue) > 0 {
   170→			return headerValue
   171→		}
   172→	}
   173→	return ""
   174→}
   175→
   176→func allHeaderValues(h http.Header, headerNames []string) []string {
   177→	ret := []string{}
   178→	for _, headerName := range headerNames {
   179→		headerKey := http.CanonicalHeaderKey(headerName)
   180→		values, ok := h[headerKey]
   181→		if !ok {
   182→			continue
   183→		}
   184→
   185→		for _, headerValue := range values {
   186→			if len(headerValue) > 0 {
   187→				ret = append(ret, headerValue)
   188→			}
   189→		}
   190→	}
   191→	return ret
   192→}
   193→
   194→func unescapeExtraKey(encodedKey string) string {
   195→	key, err := url.PathUnescape(encodedKey) // Decode %-encoded bytes.
   196→	if err != nil {
   197→		return encodedKey // Always record extra strings, even if malformed/unencoded.
   198→	}
   199→	return key
   200→}
   201→
   202→func newExtra(h http.Header, headerPrefixes []string) map[string][]string {
   203→	ret := map[string][]string{}
   204→
   205→	// we have to iterate over prefixes first in order to have proper ordering inside the value slices
   206→	for _, prefix := range headerPrefixes {
   207→		for headerName, vv := range h {
   208→			if !hasPrefixIgnoreCase(headerName, prefix) {
   209→				continue
   210→			}
   211→
   212→			extraKey := unescapeExtraKey(strings.ToLower(headerName[len(prefix):]))
   213→			ret[extraKey] = append(ret[extraKey], vv...)
   214→		}
   215→	}
   216→
   217→	return ret
   218→}
